diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index 255ce6973a16..315f70c696c2 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -3573,6 +3573,15 @@ Instruction *InstCombinerImpl::visitCallBase(CallBase &Call) {

   assert(ArgNo == Call.arg_size() && "Call arguments not processed correctly.");

+  // Try to simplify commutative calls with swapped select operands.
+  // (A ? B : C) call (A ? C : B) -> call(B, C) for commutative call
+  if (Call.arg_size() >= 2) {
+    if (Value *V = SimplifySelectsFeedingCall(Call, Call.getArgOperand(0),
+                                              Call.getArgOperand(1))) {
+      return replaceInstUsesWith(Call, V);
+    }
+  }
+
   if (!ArgNos.empty()) {
     AttributeList AS = Call.getAttributes();
     LLVMContext &Ctx = Call.getContext();
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineInternal.h b/llvm/lib/Transforms/InstCombine/InstCombineInternal.h
index bb620ad8d41c..22be70423829 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineInternal.h
+++ b/llvm/lib/Transforms/InstCombine/InstCombineInternal.h
@@ -495,6 +495,7 @@ public:
   // efficiently reorganized.
   Value *SimplifySelectsFeedingBinaryOp(BinaryOperator &I, Value *LHS,
                                         Value *RHS);
+  Value *SimplifySelectsFeedingCall(CallBase &Call, Value *Arg0, Value *Arg1);

   // (Binop1 (Binop2 (logic_shift X, C), C1), (logic_shift Y, C))
   //    -> (logic_shift (Binop1 (Binop2 X, inv_logic_shift(C1, C)), Y), C)
diff --git a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
index f072f5cec309..10340741f880 100644
--- a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
@@ -1132,6 +1132,20 @@ Value *InstCombinerImpl::SimplifySelectsFeedingBinaryOp(BinaryOperator &I,
   };

   if (LHSIsSelect && RHSIsSelect && A == D) {
+    // (A ? B : C) op (A ? C : B) -> B op C (for commutative op)
+    if (B == F && C == E && Instruction::isCommutative(Opcode)) {
+      if (Value *V = simplifyBinOp(Opcode, B, C, FMF, Q))
+        return V;
+      Value *NewBO = Builder.CreateBinOp(Opcode, B, C);
+      if (auto *OBO = dyn_cast<OverflowingBinaryOperator>(&I)) {
+        if (OBO->hasNoSignedWrap())
+          cast<BinaryOperator>(NewBO)->setHasNoSignedWrap();
+        if (OBO->hasNoUnsignedWrap())
+          cast<BinaryOperator>(NewBO)->setHasNoUnsignedWrap();
+      }
+      return NewBO;
+    }
+
     // (A ? B : C) op (A ? E : F) -> A ? (B op E) : (C op F)
     Cond = A;
     True = simplifyBinOp(Opcode, B, E, FMF, Q);
@@ -1166,6 +1180,67 @@ Value *InstCombinerImpl::SimplifySelectsFeedingBinaryOp(BinaryOperator &I,
   SI->takeName(&I);
   return SI;
 }
+Value *InstCombinerImpl::SimplifySelectsFeedingCall(CallBase &Call,
+                                                    Value *Arg0, Value *Arg1) {
+  Value *A, *B, *C, *D, *E, *F;
+  bool Arg0IsSelect = match(Arg0, m_Select(m_Value(A), m_Value(B), m_Value(C)));
+  bool Arg1IsSelect = match(Arg1, m_Select(m_Value(D), m_Value(E), m_Value(F)));
+  if (!Arg0IsSelect || !Arg1IsSelect || A != D)
+    return nullptr;
+
+  // Check if the intrinsic/call is commutative
+  bool IsCommutative = false;
+  if (auto *II = dyn_cast<IntrinsicInst>(&Call)) {
+    switch (II->getIntrinsicID()) {
+    case Intrinsic::maxnum:
+    case Intrinsic::minnum:
+    case Intrinsic::maximum:
+    case Intrinsic::minimum:
+    case Intrinsic::smax:
+    case Intrinsic::smin:
+    case Intrinsic::umax:
+    case Intrinsic::umin:
+    case Intrinsic::fma:
+    case Intrinsic::sadd_sat:
+    case Intrinsic::uadd_sat:
+    case Intrinsic::ssub_sat:
+    case Intrinsic::usub_sat:
+    case Intrinsic::smul_fix:
+    case Intrinsic::umul_fix:
+    case Intrinsic::smul_fix_sat:
+    case Intrinsic::umul_fix_sat:
+    case Intrinsic::sadd_with_overflow:
+    case Intrinsic::uadd_with_overflow:
+    case Intrinsic::ssub_with_overflow:
+    case Intrinsic::usub_with_overflow:
+    case Intrinsic::smul_with_overflow:
+    case Intrinsic::umul_with_overflow:
+      IsCommutative = true;
+      break;
+    default:
+      break;
+    }
+  } else if (Function *F = Call.getCalledFunction()) {
+    // For regular function calls, check if the function has the commutative flag
+    // or if we can determine it's commutative through other means
+    // For now, we don't handle regular function calls
+    IsCommutative = false;
+  }
+
+  if (!IsCommutative)
+    return nullptr;
+
+  // (A ? B : C) call (A ? C : B) -> call(B, C) for commutative call
+  if (B == F && C == E) {
+    SmallVector<Value *, 4> NewArgs(Call.arg_begin(), Call.arg_end());
+    NewArgs[0] = B;
+    NewArgs[1] = C;
+    return Builder.CreateCall(Call.getCalledFunction(), NewArgs);
+  }
+
+  return nullptr;
+}
+

 /// Freely adapt every user of V as-if V was changed to !V.
 /// WARNING: only if canFreelyInvertAllUsersOf() said this can be done.

